"use client";

import html2canvas from "html2canvas";
import Image from "next/image";
import { useRef, useState } from "react";
import poster from "../public/poster.png";
export default function EndorsementGenerator() {
  const posterRef = useRef<HTMLDivElement>(null);

  const [open, setOpen] = useState(false);
  const [name, setName] = useState("");
  const [preview, setPreview] = useState("");

  // HANDLE IMAGE UPLOAD
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];

    if (file) {
      const imageUrl = URL.createObjectURL(file);
      setPreview(imageUrl);
    }
  };

  // DOWNLOAD POSTER
  const handleDownload = async () => {
    if (!posterRef.current) return;

    const canvas = await html2canvas(posterRef.current, {
      scale: 3,
      useCORS: true,
    });

    const link = document.createElement("a");

    link.download = "endorsement-poster.png";
    link.href = canvas.toDataURL("image/png");

    link.click();
  };

  return (
    <div className="w-full min-h-screen flex items-center justify-center bg-gray-100 p-6">
      {/* ================= MODAL ================= */}
      {open && (
        <div className="fixed inset-0 z-50 bg-black/60 flex items-center justify-center px-4">
          <div className="bg-white w-full max-w-md rounded-2xl p-6">
            <h2 className="text-2xl font-bold mb-6">Generate Your Poster</h2>

            {/* NAME INPUT */}
            <div className="mb-4">
              <label className="block mb-2 font-medium">Your Name</label>

              <input
                type="text"
                placeholder="Enter your name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full border rounded-xl h-12 px-4 outline-none"
              />
            </div>

            {/* IMAGE INPUT */}
            <div className="mb-6">
              <label className="block mb-2 font-medium">
                Upload Your Image
              </label>

              <input
                type="file"
                accept="image/*"
                onChange={handleFileChange}
                className="w-full"
              />
            </div>

            {/* BUTTON */}
            <button
              onClick={() => setOpen(false)}
              disabled={!name || !preview}
              className="w-full h-12 rounded-xl bg-black text-white disabled:opacity-50">
              Generate Poster
            </button>
          </div>
        </div>
      )}

      {/* ================= POSTER ================= */}
      <div className=" w-full flex flex-col items-center gap-6">
        <div
          ref={posterRef}
          className="relative w-[500px] h-[650px] overflow-hidden ">
          {/* ================= YOUR POSTER GOES HERE ================= */}

          {/* BACKGROUND IMAGE */}
          {/* Replace this with your own poster */}
          <Image src={poster} alt="Poster" fill className="object-cover" />
          {/* USER IMAGE */}
          {/* {preview && (
            <img
              src={preview}
              alt="User"
              className="
                absolute
                top-[260px]
                left-1/2
                -translate-x-1/2
                w-[220px]
                h-[220px]
                rounded-full
                object-cover
                border-4
                border-white
              "
            />
          )} */}

          {/* USER NAME */}

          <div className=" absolute  top-20 h-20 w-20 bg-amber-800"></div>
        </div>

        {/* DOWNLOAD BUTTON */}
        <button
          onClick={handleDownload}
          className="h-14 px-8 rounded-xl bg-black text-white text-lg font-semibold">
          Download Poster
        </button>
      </div>
    </div>
  );
}
